mapper.insert:
/* 출석 정보 저장 */
INSERT INTO attendance_log (user_id, attendance_date)
VALUES (#{userId}, CURRENT_DATE)

mapper.select:
/* 오늘 출석 여부 확인 */
SELECT COUNT(*)
FROM attendance_log
WHERE user_id = #{userId}
  AND attendance_date = CURRENT_DATE

/* 연속 출석 일수 계산: 오늘 출석이 완료된 직후에만 호출한다.*/
WITH RECURSIVE days AS (
    -- 1. 오늘 날짜부터 시작
    SELECT CURRENT_DATE AS check_date
    UNION ALL
    -- 2. 하루씩 빼면서 기록이 있는지 확인 (연속되지 않으면 멈춤)
    SELECT (check_date - INTERVAL '1 day')::DATE
    FROM days
    WHERE EXISTS (
        SELECT 1 FROM attendance_log
        WHERE user_id = #{userId}
          AND attendance_date = (check_date - INTERVAL '1 day')::DATE
    )
)
SELECT COUNT(*) FROM days;
